import{_ as p}from"./plugin-vue_export-helper-c27b6911.js";import{o as a,c as e,f as r}from"./app-6b22766f.js";const t={},h=r('<h1 id="_12-资源的极致使用" tabindex="-1"><a class="header-anchor" href="#_12-资源的极致使用" aria-hidden="true">#</a> #12 资源的极致使用</h1><h2 id="一" tabindex="-1"><a class="header-anchor" href="#一" aria-hidden="true">#</a> 一</h2><p>什么样的人可以对资源进行极致利用？大师！</p><p>之前看的小说里，有一种职业叫炼丹师。</p><p>他们利用火焰炼丹，炼丹的过程中，必须全神贯注，精妙的操纵火焰，一点点融合灵草&amp;精华&amp;天材地宝。对于其中真正的高手，我们称其为“大师”。这样的丹药成型的时候，会散发出丹药的异香。</p><p>大师就是擅长微操的人，大师就是能把资源利用到极限，能开发出不同技能树的人。<br> 这世界上本没有流派，有一个大师走过，于是便有了流派。</p><p>人生没有炼丹，但是人活在世上，有无数种和炼丹相同的事情。</p><p>例如求职、跳槽、创业、谈判、招商、降本、软件构建、性能优化、互联网、投资、电商、AI、流量，以及包括点外卖。</p><h2 id="二" tabindex="-1"><a class="header-anchor" href="#二" aria-hidden="true">#</a> 二</h2><p>谈判有大师也就算了，毕竟有的人谈判起来确实可以一点点的为自己争取到最大利益。性能优化自然也是有大师的，例如梁文峰想必是性能优化和量化的双重大师。</p><p>但是点外卖也有大师？？</p><p>在对券的理解上胜你一筹，在每个平台的角落里找到合适的券，在各个平台之间切来切去，在有外卖活动的时候一期不落，预约下单以消耗更多的券，用更少的时间完成抢券动作。</p><p>你的点奶茶平均成本是多少，可能是20，如果你随手领券可能是18左右。</p><p>而点外卖的大师，能降这个平均成本压到12。</p><p>看似只是18-&gt;12，但是其中的差别，就是33%。这33%，如果在外卖的消费上而言，人家就可以永远比你便宜33%，这33%就相当于对方多省了33%的钱，永远可以比你多吃更多东西。</p><p>对于生意，33%就是生死线。</p><p>对于量化，33%就是巨大的利润。<br> 之前有炒房子的大师曾经说，买房子没有什么真正的心法，最核心的就是实打实看房两百套。</p><p>量化也没有什么心法，回测一千次就可以提升5%的收益。</p><p>点外卖虽然是一件小事，但是这背后折射出来的是把资源利用到极致。</p><h2 id="三" tabindex="-1"><a class="header-anchor" href="#三" aria-hidden="true">#</a> 三</h2><p>从某种意义上来说，今天能把抢券做好的人，下一步也就可以把其他的资源利用好。</p><p>在本博客官网，我有一个Slogan：”我们的生活中还有很大的优化空间“。这些优化空间从哪里来，就从这个地方来。<br> 任何时候都可以想一想，还有什么资源没有利用到极致？</p><p>家里的电脑是不是基本上都在休息？<br> 家里闲置的房间是不是没有租出去？<br> 每天的钱是不是躺在活期里睡大觉？</p><p>如果你只会在职场上成捆的出售自己的时间，你的资源，一定没有利用到极致。</p>',24),d=[h];function _(n,c){return a(),e("div",null,d)}const s=p(t,[["render",_],["__file","12 资源的极致使用.html.vue"]]);export{s as default};
